1	/**
2	 * `revealTodos` stage. Active once `onboarding_todos` is non-empty and the
3	 * user hasn't acked yet.
4	 *
5	 * Two sub-states:
6	 * - **Grid mode** (default): show the suggested todos. User can click "Run"
7	 *   on one (→ `executeTodo`, flips into stream mode) or "I'll do it later"
8	 *   (→ `ackTodos`, advances to workflows).
9	 * - **Stream mode** (`state.todoExecutionStarted`): the todo grid is replaced
10	 *   in-place by the live chat stream so the agent's processing is visible
11	 *   without leaving the onboarding shell. Once the agent finishes
12	 *   (`chat.isTodoExecutionDone`) a Continue button dispatches `ackTodoDemo`
13	 *   to advance to the workflows stage.
14	 */
15	
16	"use client";
17	
18	import { Button } from "@heroui/button";
19	import * as m from "motion/react-m";
20	import type { Dispatch } from "react";
21	import { useCallback } from "react";
22	import { REVEAL_TODOS_INTRO } from "../../constants/messages";
23	import type { UseOnboardingChatReturn } from "../../hooks/useOnboardingChat";
24	import type { Action, OnboardingState } from "../../state/types";
25	import { OnboardingCTAButton } from "../OnboardingCTAButton";
26	import { OnboardingTodoCards } from "../OnboardingTodoCards";
27	import { RevealIntroBubble } from "../RevealIntroBubble";
28	import { OnboardingChatStream } from "./Chat";
29	
30	interface RevealTodosProps {
31	  state: OnboardingState;
32	  dispatch: Dispatch<Action>;
33	  chat: UseOnboardingChatReturn;
34	}
35	
36	export function RevealTodos({ state, dispatch, chat }: RevealTodosProps) {
37	  const todos = state.server?.onboarding_todos ?? [];
38	
39	  const handleExecute = useCallback(
40	    (todoId: string) => {
41	      const todo = todos.find((t) => t.id === todoId);
42	      if (!todo) return;
43	      const sourceEmail = todo.source_email ?? null;
44	      const emailHint = sourceEmail
45	        ? `\n\n[Context: derived from an email from "${sourceEmail.sender}" with subject "${sourceEmail.subject}". Reference this email and its actual contents.]`
46	        : "";
47	      const closingHint =
48	        "\n\n[This is an onboarding run-now demo. Execute the todo and report the result in 1-2 short sentences. Do NOT ask a follow-up question. Do NOT offer further help or automation. End on the result.]";
49	      const message = `Execute this todo for me: ${todo.title}${emailHint}${closingHint}`;
50	      dispatch({
51	        type: "executeTodo",
52	        message,
53	        todo: { id: todo.id, title: todo.title, sourceEmail },
54	      });
55	    },
56	    [todos, dispatch],
57	  );
58	
59	  if (todos.length === 0) return null;
60	
61	  if (state.todoExecutionStarted) {
62	    const executingTodo = state.todoExecutionTodo
63	      ? todos.find((t) => t.id === state.todoExecutionTodo?.id)
64	      : null;
65	    const done = chat.isTodoExecutionDone;
66	    return (
67	      <m.div
68	        className="mt-10 w-full space-y-4"
69	        initial={{ opacity: 0 }}
70	        animate={{ opacity: 1 }}
71	        transition={{ duration: 0.3 }}
72	      >
73	        {executingTodo && (
74	          <OnboardingTodoCards
75	            todos={[
76	              {
77	                id: executingTodo.id,
78	                title: executingTodo.title,
79	                description: executingTodo.description ?? undefined,
80	                source_email: executingTodo.source_email ?? undefined,
81	              },
82	            ]}
83	            onExecuteTodo={() => {}}
84	            isExecuting={!done}
85	            executingTodoId={done ? null : executingTodo.id}
86	            completedTodoIds={done ? new Set([executingTodo.id]) : new Set()}
87	            readOnly
88	          />
89	        )}
90	        <OnboardingChatStream
91	          chat={chat}
92	          todoOverride={state.todoExecutionTodo}
93	        />
94	
95	        {chat.isTodoExecutionDone && (
96	          <m.div
97	            className="flex justify-center pt-2"
98	            initial={{ opacity: 0, y: 4 }}
99	            animate={{ opacity: 1, y: 0 }}
100	            transition={{ duration: 0.4 }}
101	          >
102	            <OnboardingCTAButton
103	              onClick={() => dispatch({ type: "ackTodoDemo" })}
104	            >
105	              Continue
106	            </OnboardingCTAButton>
107	          </m.div>
108	        )}
109	      </m.div>
110	    );
111	  }
112	
113	  return (
114	    <div className="mt-3 space-y-4">
115	      <RevealIntroBubble text={REVEAL_TODOS_INTRO}>
116	        <OnboardingTodoCards
117	          todos={todos.map((t) => ({
118	            id: t.id,
119	            title: t.title,
120	            description: t.description ?? undefined,
121	            source_email: t.source_email ?? undefined,
122	          }))}
123	          onExecuteTodo={handleExecute}
124	          isExecuting={false}
125	          executingTodoId={null}
126	          completedTodoIds={new Set()}
127	        />
128	      </RevealIntroBubble>
129	
130	      <m.div
131	        className="flex justify-center"
132	        initial={{ opacity: 0 }}
133	        animate={{ opacity: 1 }}
134	        transition={{ delay: 1.5, duration: 0.4 }}
135	      >
136	        <Button
137	          variant="light"
138	          size="sm"
139	          className="text-xs text-zinc-400 hover:text-zinc-200"
140	          onPress={() => dispatch({ type: "ackTodos" })}
141	        >
142	          I'll do it later
143	        </Button>
